package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testGetCommentMarkerWhenNull() {
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertNull(format.getCommentMarker());
    }

    @Test
    void testGetCommentMarkerWhenSet() {
        char commentChar = '#';
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(commentChar);
        assertNotNull(format.getCommentMarker());
        assertEquals(Character.valueOf(commentChar), format.getCommentMarker());
    }

    @Test
    void testGetCommentMarkerWithCharacterObject() {
        Character commentChar = Character.valueOf('!');
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker(commentChar);
        assertNotNull(format.getCommentMarker());
        assertEquals(commentChar, format.getCommentMarker());
    }
}
